60	        && ngx_use_epoll_rdhup)
61	    {
62	        ngx_log_debug2(NGX_LOG_DEBUG_EVENT, c->log, 0,
63	                       "readv: eof:%d, avail:%d",
64	                       rev->pending_eof, rev->available);
65	
66	        if (rev->available == 0 && !rev->pending_eof) {
67	            rev->ready = 0;
