74	    prev = NULL;
75	    iov = NULL;
76	    size = 0;
77	
78	    vec.elts = iovs;
79	    vec.nelts = 0;
80	    vec.size = sizeof(struct iovec);
81	    vec.nalloc = NGX_IOVS_PREALLOCATE;
82	    vec.pool = c->pool;
83	
84	    /* coalesce the neighbouring bufs */
85	
86	    while (chain) {
