32	     *     b->file = NULL;
33	     *     b->shadow = NULL;
34	     *     b->tag = 0;
35	     *     and flags
36	     */
37	
38	    b->pos = b->start;
39	    b->last = b->start;
40	    b->end = b->last + size;
41	    b->temporary = 1;
42	
