70	{
71	    u_char       *p;
72	    ngx_int_t     i;
73	    ngx_buf_t    *b;
74	    ngx_chain_t  *chain, *cl, **ll;
75	
76	    p = ngx_palloc(pool, bufs->num * bufs->size);
77	    if (p == NULL) {
78	        return NULL;
79	    }
80	
81	    ll = &chain;
82	
83	    for (i = 0; i < bufs->num; i++) {
84	
85	        b = ngx_calloc_buf(pool);
86	        if (b == NULL) {
87	            return NULL;
88	        }
89	
90	        /*
91	         * set by ngx_calloc_buf():
92	         *
93	         *     b->file_pos = 0;
94	         *     b->file_last = 0;
95	         *     b->file = NULL;
96	         *     b->shadow = NULL;
97	         *     b->tag = 0;
98	         *     and flags
99	         *
100	         */
101	
102	        b->pos = p;
103	        b->last = p;
104	        b->temporary = 1;
105	
106	        b->start = p;
107	        p += bufs->size;
108	        b->end = p;
109	
110	        cl = ngx_alloc_chain_link(pool);
111	        if (cl == NULL) {
112	            return NULL;
113	        }
114	
115	        cl->buf = b;
116	        *ll = cl;
117	        ll = &cl->next;
118	    }
119	
120	    *ll = NULL;
121	
122	    return chain;
123	}
