127	ngx_chain_add_copy(ngx_pool_t *pool, ngx_chain_t **chain, ngx_chain_t *in)
128	{
129	    ngx_chain_t  *cl, **ll;
130	
131	    ll = chain;
132	
133	    for (cl = *chain; cl; cl = cl->next) {
134	        ll = &cl->next;
135	    }
