139	        if (cl == NULL) {
140	            *ll = NULL;
141	            return NGX_ERROR;
142	        }
143	
144	        cl->buf = in->buf;
145	        *ll = cl;
146	        ll = &cl->next;
147	        in = in->next;
148	    }
149	
150	    *ll = NULL;
151	
152	    return NGX_OK;
153	}
